CREATE TABLE `prod_unidade_turistica` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `nome` varchar(255) NOT NULL,
  `nome_fantasia` varchar(255) DEFAULT NULL,
  `razao_social` varchar(255) DEFAULT NULL,
  `cnpj` varchar(20) DEFAULT NULL,
  `setor` varchar(100) DEFAULT NULL,
  `endereco` varchar(500) DEFAULT NULL,
  `id_bairro` int(11) DEFAULT NULL,
  `latitude` decimal(10,8) NOT NULL,
  `longitude` decimal(11,8) NOT NULL,
  `telefone` varchar(100) DEFAULT NULL,
  `whatsapp` varchar(100) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `horario_funcionamento` text DEFAULT NULL,
  `descricao_servicos` text DEFAULT NULL,
  `imagem_url` varchar(500) DEFAULT NULL,
  `icone_url` varchar(500) DEFAULT NULL,
  `data_cadastro` datetime(3) DEFAULT NULL,
  `data_vencimento` datetime(3) DEFAULT NULL,
  `ativo` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `updated_at` datetime(3) NOT NULL,
  `diretor_adjunto` varchar(255) DEFAULT NULL,
  `diretor_responsavel` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `prod_unidade_turistica_ativo_idx` (`ativo`),
  KEY `prod_unidade_turistica_id_bairro_idx` (`id_bairro`),
  KEY `prod_unidade_turistica_latitude_longitude_idx` (`latitude`,`longitude`),
  KEY `prod_unidade_turistica_setor_idx` (`setor`),
  CONSTRAINT `prod_unidade_turistica_id_bairro_fkey` FOREIGN KEY (`id_bairro`) REFERENCES `prod_bairro` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=340 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
