  (160,'PS - Pronto Socorro Dr. Rogério Takaki Bento','Pronto Socorro Dr Rogério Takaki Bento',NULL,NULL,'Outro','Rua América s/n',3,-19.00562982,-57.65391204,NULL,'(67) 98191-0103',NULL,'Sempre Aberto',NULL,'/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Serviço Emergência.png',NULL,NULL,1,'2026-01-20 14:07:56.000','2026-01-31 22:47:55.199',NULL,NULL)),
  (161,'SAMU - Serviço Médico de Urgência','SAMU - Serviço Médico de Urgência',NULL,NULL,'Outro','Rua Nsra da Candelária, s/n°',17,-19.00202020,-57.62643988,'192',NULL,NULL,'Sempre Aberto','Serviço gratuito de socorro, disponível 24 horas, acionado pelo telefone 192 para emergências graves de natureza clínica, traumática, obstétrica, pediátrica ou psiquiátrica','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Serviço Emergência.png',NULL,NULL,1,'2026-01-20 14:07:56.000','2026-01-31 22:53:55.106',NULL,NULL)),
  (162,'Santa Casa de Corumbá - Hospital','Santa Casa de Corumbá',NULL,NULL,'Outro','Rua 15 de Novembro entre Ruas Cabral e América',3,-19.00553422,-57.65391771,NULL,NULL,NULL,NULL,'Principal unidade hospitalar e referência de saúde na região pantaneira de Mato Grosso do Sul. Trata-se de uma instituição filantrópica que atua no atendimento a enfermos, contando com UTI, exames de laboratório/imagem entre outros serviços.','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Serviço Emergência.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-01-31 22:56:06.468',NULL,NULL)),
  (163,'UPA - Unidade de Pronto Atendimento Dr José Abílio M. de Barros ','Unidade de Pronto Atendimento Dr José Abílio M. de Barros - UPA',NULL,NULL,'Outro','Luiz Feitosa Rodrigues, s/n',12,-19.04694697,-57.64504910,NULL,NULL,NULL,NULL,NULL,'/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Serviço Emergência.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-04 14:21:12.417',NULL,NULL)),
  (164,'Museu de História do Pantanal','Museu de História do Pantanal',NULL,NULL,'Ponto Turístico','R. Manoel Cavassa, 275 - Centro, Corumbá - MS, 79301-120',3,-18.99736320,-57.65450040,NULL,NULL,NULL,NULL,'O MUHPAN (Museu de História do Pantanal) possibilita o acesso a um vasto acervo sobre aspectos naturais, arqueológicos, históricos, de ocupação humana e cultural da maior planície alagada do mundo, o Pantanal.  ','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-01 02:34:43.184',NULL,NULL)),
  (165,'Casa do Dr. Gabi - Espaço de Memória ','Casa do Dr. Gabi - Espaço de Memória ',NULL,NULL,'Ponto Turístico','R. Cuiabá, 1181, Corumbá - MS',3,-19.00375264,-57.65345616,NULL,NULL,NULL,NULL,'Inaugurado em 2016, é um importante ponto turístico, cultural e histórico em Corumbá (MS). Homenageia Dr. Gabriel Vandoni de Barros, figura local que incentivou a cultura e educação, oferecendo exposições, oficinas e eventos, além de abrigar a \"Casa do Poeta\". ','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-01 02:32:08.222',NULL,NULL)),
  (166,'Memorial do Homem Pantaneiro','Memorial do Homem Pantaneiro',NULL,NULL,'Ponto Turístico','Ladeira José Bonifácio, 171, Corumbá - MS',3,-18.99771816,-57.65533436,NULL,NULL,NULL,NULL,'Localizado no histórico casarão Casa Vasquez & Filhos no Porto Geral de Corumbá (MS), no Porto Geral, é um centro cultural de acesso gratuito que valoriza a cultura e tradições rurais do bioma. Aberto de terça a sexta (15h-18h) e fins de semana (manhã), destaca a vida dos pantaneiros com exposições fotográficas. ','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-01 02:34:07.077',NULL,NULL)),
  (167,'Casa do Artesão','Casa do Artesão',NULL,NULL,'Ponto Turístico','R. Dom Aquino Correa, 405, Corumbá - MS',3,-19.00017225,-57.64692214,NULL,NULL,NULL,NULL,'Centro cultural e comercial situado em um antigo presídio do final do século XIX (funcionou de 1905 a 1970). O prédio preserva suas antigas celas, que foram transformadas em ateliês e lojas para a comercialização de artesanato local, representando um marco na valorização da cultura e economia criativa pantaneira. ','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Restaurante Multisserviços.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-03 14:53:35.727',NULL,NULL)),
  (168,'Cristo Rei do Pantanal - Complexo Mirante Izulina Xavier','Cristo Rei do Pantanal - Complexo Mirante Izulina Xavier',NULL,NULL,'Ponto Turístico','Alameda Dezessete Bc, 140, Corumbá - MS',19,-19.01869386,-57.64036796,NULL,NULL,NULL,NULL,'Monumento religioso e ponto turístico de 12 metros de altura, localizado no topo do Morro do Cruzeiro em Corumbá, Mato Grosso do Sul. Inaugurado em 2004, a estátua foi criada pela artista plástica Izulina Xavier e oferece uma vista panorâmica de 360 graus da região, incluindo o Rio Paraguai, Ladário e a fronteira com a Bolívia. \n\nO Complexo Mirante Izulina Xavier é composto 72 estatuas, sendo 71 representando a Via Sacra (cada estatua tem, em média, 2 m de altura) e a estátua do Cristo Rei do Pantanal (com 12 m de altura). O trajeto para chegar ao Cristo Rei também é um atrativo à parte. Ao longo do caminho, esculturas de Izulina Xavier representam as 14 estações da Paixão de Cristo.\n\n* Atrativo turístico com acesso para veículos, estrutura com banheiros e estacionamento.','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-01 02:33:25.651',NULL,NULL)),
  (169,'Jardim da Independência','Jardim da Independência',NULL,NULL,'Ponto Turístico','Rua Frei Mariano, Corumbá',3,-19.00099854,-57.65320002,NULL,NULL,NULL,NULL,'Localizado no centro de Corumbá, MS, é um dos principais pontos turísticos da cidade, conhecido por sua arquitetura histórica, portões de ferro importados da Alemanha e muradas de mármore. Projetado em estilo Glaziou, o local abriga árvores centenárias, espelhos d\'água, um coreto octogonal e esculturas em mármore Carrara representando as 4 estações do ano. \n\nUm ponto de encontro agradável para os moradores e um local de visita obrigatória para conhecer o patrimônio cultural e histórico de Corumbá. ','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-01 02:36:48.954',NULL,NULL)),
  (170,'Praça da República','Praça da República',NULL,NULL,'Ponto Turístico','R. Delamare - Corumbá MS',3,-18.99834852,-57.65118421,NULL,NULL,NULL,NULL,'Localizada no centro de Corumbá (MS), é um dos principais espaços históricos e turísticos da cidade, marcando o local da retomada brasileira na Guerra do Paraguai em 1867. Com cerca de 6.000 m², abriga um obelisco em mármore, áreas arborizadas e fica próxima à Igreja Matriz de Nossa Senhora da Candelária. ','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-01 02:37:14.309',NULL,NULL)),
  (171,'Praça Generoso Ponce','Praça Generoso Ponce',NULL,NULL,'Ponto Turístico','R. Gen. Rondon, 168-322, Corumbá - MS',3,-18.99821964,-57.65548180,NULL,NULL,NULL,NULL,'Localizada no centro histórico de Corumbá (MS), é um marco urbano tombado pelo IPHAN, próximo a importantes atrações como o casario do Porto Geral, a Casa do Artesão e o Museu de História do Pantanal (MUHPAN). A região é central para o turismo cultural e histórico, conectando visitantes à orla e ao charmoso cenário urbano da \"Capital do Pantanal\". \n\nA praça é palco constante de eventos, como o Carnaval (escolha da Corte de Momo), festivais, shows musicais (como no aniversário da cidade) e o Festival América do Sul Pantanal.','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-01 02:36:28.254',NULL,NULL)),
  (172,'Porto Geral / Centro Histórico','Porto Geral / Centro Histórico',NULL,NULL,'Ponto Turístico','R. Manoel Cavassa, Beira-Rio - Corumbá - MS',3,-18.99678014,-57.65339912,NULL,NULL,NULL,NULL,'É um dos principais cartões-postais da cidade, oferecendo um casario histórico, passeios de barco pelo Rio Paraguai, lojinhas de artesanato, museus (MUHPAN), memorial (Memorial do Homem Pantaneiro) e restaurantes típicos com vista para o Pantanal. É ideal para caminhar ao pôr do sol, visitar a orla e viver a cultura histórica e pantaneira. ','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-01 02:35:18.375',NULL,NULL)),
  (173,'Feiras Livre - Segunda-feira','Feiras Livre (alimentos e Brechó) - Segunda',NULL,NULL,'Ponto Turístico','Rua Paraná, esquina com Rua Frei Mariano',7,-19.02515474,-57.64333248,NULL,NULL,NULL,NULL,' Um tradicional ponto de encontro urbano, famoso pelo pastel de feira de massa fina, crocante e recheio generoso. É onde também  encontrará as suculentas saltenhas, tradicional em Corumbá (MS) e típica da Bolívia, influenciado pela fronteira. Um tipo de pastel assado, com massa adocicada e recheio caldoso (geralmente carne ou frango). \n\nAlém de quitutes e especiarias, também são presentes os produtos frescos, o queijo Nicola (queijo artesanal típico do Pantanal), hortifrutis e brechó a céu aberto. Funciona em diversos locais da cidade, sendo a de domingo no centro a principal, atraindo moradores e turistas. ','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-02-03 14:17:42.641',NULL,NULL)),
  (174,'Feira Livre - Terça-feira','Feiras Livre (alimentos e Brechó) - Terça',NULL,NULL,'Ponto Turístico','Rua Dom Pedro I, esquina com Rua José Fragelli',16,-19.02404917,-57.65961885,NULL,NULL,NULL,NULL,'Um tradicional ponto de encontro urbano, famoso pela saltenha tradicional em Corumbá (MS) que é típica da Bolívia, influenciado pela fronteira. Um tipo de pastel assado, com massa adocicada e recheio caldoso (geralmente carne ou frango). \n\nAlém de quitutes e especiarias, também são presentes os produtos frescos, o queijo Nicola (queijo artesanal típico do Pantanal), hortifrutis e brechó a céu aberto. Funciona em diversos locais da cidade, sendo a de domingo no centro a principal, atraindo moradores e turistas. ','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-01-20 14:07:57.000','2026-01-31 22:26:15.976',NULL,NULL)),
