  (186,'Guarda Civil Municipal','Guarda Civil Municipal',NULL,NULL,'Apoio e Emergência','R. Jose Sabino Da Costa, 335 - Generoso, Corumbá - MS, 79333-078 ',11,-18.99896300,-57.67031900,'153','(67) 3907-5323','guardamunicipal@corumba.ms.gov.br','Atendimento ao Público: 07h30 às 13h30 \nPlantão: 24h','Responsável por auxiliar as demais forças de segurança na manutenção da ordem pública, bem como cuidar dos bens, serviços e instalações e da integridade física dos cidadãos atuando de forma ostensiva preventiva na cidade.','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Serviço Emergência.png',NULL,NULL,1,'2026-01-26 12:03:32.000','2026-01-31 22:28:25.284',NULL,NULL)),
  (187,'Patrulha Maria da Penha - Corumbá ','Patrulha Maria da Penha - Corumbá ',NULL,NULL,'Apoio e Emergência','Rua XV de Novembro, 659',3,-19.00336300,-57.65711400,NULL,'(67) 99940-8672','patrulhamariadapenha@corumba.ms.gov.br','Sempre Aberta','Atua permanente e regular, na proteção, prevenção, fiscalização, monitoramento e acompanhamento das mulheres vítimas de violência doméstica ou familiar que possuam medidas protetivas de urgência, integrando as ações realizadas pela Rede de Atendimento à Mulher em situação de violência na Cidade de Corumbá.','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Serviço Emergência.png',NULL,NULL,1,'2026-01-26 12:03:33.000','2026-01-31 22:42:12.471',NULL,NULL)),
