  (189,'Delegacia de Atendimento à Mulher de Corumbá','Delegacia de Atendimento à Mulher de Corumbá',NULL,NULL,'Apoio e Emergência','Rua Major Gama, nº 290 Centro',3,-19.00067534,-57.65776552,'(67) 3234-9904',NULL,'damcorumba@pc.ms.gov.br','Para denúncias, informações e serviços especializados, a orientação é buscar a unidade na rua Major Gama durante o horário comercial, ou a Polícia Militar (190) para casos urgentes fora desse horário.',NULL,'/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Serviço Emergência.png',NULL,NULL,1,'2026-01-26 12:03:33.000','2026-01-31 22:22:08.528',NULL,NULL)),
