  (193,'AGETRAT - Agência Municipal de Trânsito e Transporte','AGETRAT',NULL,NULL,'Apoio e Emergência','Rua João Afonso, 361',19,-19.01588200,-57.64975000,NULL,'(67) 99633-9709','agetrat@corumba.ms.gov.br','Atendimento Presencial:\nSegunda-Feira a Sexta-Feira: 07:30 às 13:30\n\n🚦 Fiscalização de Trânsito – Plantão Ocorrências, denúncias, sinistros, situações de risco e atendimentos urgentes: \n📲 (67) 99633-9709','Fiscalização de trânsito e transporte\nEmissão de credencial de estacionamento especial para idoso ou deficiente físico\nImplantação e manutenção de sinalização de trânsito\nRecebimento de recursos de notificações (JADA/ JARI / JARIT)\nAções educativas de trânsito\nVistorias veiculares (trio elétrico, ônibus, taxis, Mototáxi, motoristas de aplicativos e outros).\n ','/uploads/imagem_Padrão_Mapas_Carnaval_2026.png','/uploads/icones/Serviço Emergência.png',NULL,NULL,1,'2026-01-26 12:03:34.000','2026-01-31 22:12:45.356',NULL,NULL)),
