  (306,'Al Arabe - Culinária Libanesa','Al Arabe - Culinária Libanesa',NULL,NULL,'RESTAURANTE','R. Cuiabá, 2305 - Dom Bosco, Corumbá - MS, 79333-090',10,-19.00667915,-57.66368801,NULL,NULL,NULL,NULL,'🗣️A verdadeira culinária Libanesa no Manara Shopping\n📍Manara Shopping. Rua Cuiaba 2322',NULL,'/uploads/icones/Pizzaria.png',NULL,NULL,1,'2026-01-31 23:22:58.760','2026-02-03 17:37:34.972',NULL,NULL)),
  (307,'Casa A - Ócio e Cultura','Casa A - Ócio e Cultura',NULL,NULL,NULL,NULL,22,-18.99635414,-57.65296499,NULL,NULL,NULL,NULL,'A Casa A - Ócio e Cultura é um espaço de compartilhamento, autorias e vivência cultural situado em Corumbá, MS, focado em promover atividades de lazer, cultura e música. Localizada na Rua Manoel Cavassa, 127 (no Porto Geral), a empresa atua na organização de eventos, feiras e exposições de arte, com funcionamento de quarta a domingo. \n\nNo espaço funciona o Café Bistrô Dandalu, oferecendo bolos artesanais, doces e cafés em horários específicos (quarta a sábado, 16h -21h; domingo, 9h-13h). ',NULL,'/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-02-01 00:56:40.162','2026-02-01 02:30:43.377',NULL,NULL)),
  (311,'Pousada Amolar Experience - Programa de Turismo ','Pousada Amolar Experience - Programa de Turismo ',NULL,NULL,NULL,'Ladeira José Bonifácio, 171 - Beira-Rio, Corumbá - MS, 79300-010',22,-18.99733428,-57.65537139,'(67) 3232-3303','(67) 4042-5424','faleconosco@institutohomempantaneiro.org.br',NULL,'* Pousada situada na região da Serra do Amolar, no Pantanal Sul, próximo à divisa dos estados de Mato Grosso do Sul e Mato Grosso.\n\n* O Programa Amolar Experience tem como principal objetivo a promoção e produção de experiências turísticas inovadoras e sustentáveis na Serra do Amolar e seu entorno. O Programa Amolar Experience é gerido pelo Instituto Homem Pantaneiro.',NULL,'/uploads/icones/Lanchonete.png',NULL,NULL,1,'2026-02-01 01:21:37.414','2026-02-01 03:06:39.868',NULL,NULL)),
  (312,'A Caimasul – Caimans do Sul do Pantanal ','A Caimasul – Caimans do Sul do Pantanal ',NULL,NULL,'OUTRO','BR MS 262 - Km 741 - Zona Rural, MS',8,-19.28896042,-57.62700506,NULL,'(67) 99814-8505','luizricardo@lrtravelexperience.com','🐊 Agendamentos e Reservas: Sempre Aberto ','🐊Inovação, tecnologia e natureza marcarão seu circuito pela CAIMASUL, maior fazenda de criação de jacarés do mundo.\n\n🐊As surpresas e a partilha de conhecimento sobre um dos ícones da fauna pantaneira, o jacaré, somam-se em passeio encantador com duração de 3h30. A fazenda localiza-se a 35km da cidade de Corumbá, por via asfaltada (BR-262).',NULL,'/uploads/icones/Imersão Pesca - Pousadas.png',NULL,NULL,1,'2026-02-01 01:46:26.542','2026-02-03 12:59:14.653',NULL,NULL)),
